  Future<void> _toggleSync(bool value) async {
    setState(() {
      _isSyncEnabled = value;
    });

    if (value) {
      _log("Initializing Secure P2P Engine...");
      final devName = _nameController.text.trim();

      if (Platform.isAndroid) {
        try {
          final bool? hasOverlay = await _serviceChannel.invokeMethod<bool>('checkOverlayPermission');
          if (hasOverlay != null && !hasOverlay) {
            _log("Overlay permission not granted.");
            final proceed = await _showOverlayPermissionExplainDialog();
            if (proceed) {
              await _serviceChannel.invokeMethod('requestOverlayPermission');
              _log("Opening overlay settings. Please enable display over other apps.");
            }
          }
        } catch (e) {
          _log("Overlay permission check error: $e");
        }

        try {
          final bool? ignoringBattery = await _serviceChannel.invokeMethod<bool>('checkBatteryOptimization');
          if (ignoringBattery != null && !ignoringBattery) {
            _log("Battery optimization is enabled.");
            final proceed = await _showBatteryOptimizationExplainDialog();
            if (proceed) {
              await _serviceChannel.invokeMethod('requestDisableBatteryOptimization');
              _log("Requesting to ignore battery optimizations...");
            }
          }
        } catch (e) {
          _log("Battery optimization check error: $e");
        }

        try {
          await _serviceChannel.invokeMethod('startForegroundService');
        } catch (e) {
          _log("Foreground service error: $e");
        }
      }

      // Resolve secure storage directory path
      String storageDir = "/home/sanal-sivakumar/Documents/clipboard";
      if (Platform.isLinux) {
        final home = Platform.environment['HOME'];
        storageDir = home != null ? "$home/.config/syncboard" : Directory.current.path;
      } else if (Platform.isAndroid) {
        storageDir = "/data/data/com.example.clipboard/files";
      } else if (Platform.isIOS) {
        storageDir = "${Directory.systemTemp.path}/syncboard";
      }

      await Directory(storageDir).create(recursive: true);

      String platformStr = "linux";
      if (Platform.isAndroid) {
        platformStr = "android";
      } else if (Platform.isIOS) {
        platformStr = "ios";
      }

      try {
        await api.startSync(
          storageDir: storageDir,
          deviceName: devName.isEmpty ? "Secured Peer" : devName,
          platform: platformStr,
          deviceId: _deviceId,
        );
        _log("P2P server running. Local Storage: $storageDir");

        if (Platform.isAndroid) {
          _startAndroidClipboardPoller();
        } else if (Platform.isIOS) {
          try {
            await _clipboardChannel.invokeMethod('startSilentAudio');
            _log("Background silent audio started.");
          } catch (e) {
            _log("Failed to start silent audio: $e");
          }
          _startIosClipboardPoller();
        }

        _startSyncUiRefresher();
      } catch (e) {
        _log("Sync initialization failed: $e");
      }
    } else {
      _log("Shutting down P2P sync...");
      _androidClipboardTimer?.cancel();
      _iosClipboardTimer?.cancel();
      _uiRefreshTimer?.cancel();

      if (Platform.isAndroid) {
        try {
          await _serviceChannel.invokeMethod('stopForegroundService');
        } catch (e) {
          _log("Failed to stop foreground service: $e");
        }
      } else if (Platform.isIOS) {
        try {
          await _clipboardChannel.invokeMethod('stopSilentAudio');
          _log("Background silent audio stopped.");
        } catch (e) {
          _log("Failed to stop silent audio: $e");
        }
        try {
          await api.handleAppBackground();
        } catch (e) {
          _log("Failed to suspend Rust engine: $e");
        }
      }

      setState(() {
        _discoveredPeers = [];
        _trustedPeers = [];
      });
    }
  }

  void _startSyncUiRefresher() {
    _uiRefreshTimer?.cancel();
    _uiRefreshTimer = Timer.periodic(const Duration(seconds: 2), (timer) async {
      if (!_isSyncEnabled) return;
      try {
        final discList = await api.getDiscoveredPeers();
        final trustList = await api.getTrustedPeers();
        setState(() {
          _discoveredPeers = discList;
          _trustedPeers = trustList;
        });
      } catch (_) {
        // Skips updating if libraries aren't ready
      }
    });
  }

  void _startAndroidClipboardPoller() {
    _androidClipboardTimer?.cancel();
    _androidClipboardTimer = Timer.periodic(const Duration(milliseconds: 500), (timer) async {
      if (!_isSyncEnabled) return;
      try {
        final clipData = await Clipboard.getData(Clipboard.kTextPlain);
        final text = clipData?.text;

        if (text != null && text.isNotEmpty && text != _lastClipboardText) {
          _lastClipboardText = text;
          _log("Local clip changed: '${text.length > 25 ? '${text.substring(0, 25)}...' : text}'");
          try {
            await api.sendLocalClipboardUpdate(content: text);
          } catch (e) {
            _log("Clipboard broadcast error: $e");
          }
        }
      } catch (e) {
        debugPrint("Android Clipboard poll error: $e");
      }
    });
  }

  bool _isPeerTrusted(String peerId) {
    return _trustedPeers.any((tp) => tp.deviceId == peerId);
  }

