          ElevatedButton(
            onPressed: () {
              api.unpairDevice(peerId: peerId);
              Navigator.pop(context);
              _log("Device $name unpaired and untrusted.");
            },
            style: ElevatedButton.styleFrom(backgroundColor: Colors.red),
            child: const Text("Unpair"),
          ),
        ],
      ),
    );
  }
